function normalizeLocaleTag(value) {
	if (!value) return "en";
	var tag = String(value).trim().replace("_", "-");
	if (!tag) return "en";
	var idx = tag.indexOf("-");
	if (idx !== -1) {
		tag = tag.slice(0, idx);
